int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int n, m;
    cin >> n >> m;
    vector<vector<pair<int,long long>>> g(n);
    for (int i = 0; i < m; ++i) {
        int u, v;
        long long w;
        cin >> u >> v >> w;
        --u; --v;
        g[u].push_back({v, w});
        g[v].push_back({u, w});
    }
    vector<int> used(n, 0);
    long long ans = numeric_limits<long long>::max();
    function<void(int,long long)> dfs = [&](int v, long long xr) {
        if (v == n - 1) {
            ans = min(ans, xr);
            return;
        }
        used[v] = 1;
        for (auto [to, w] : g[v]) if (!used[to]) dfs(to, xr ^ w);
        used[v] = 0;
    };
    dfs(0, 0);
    cout << ans << '\n';
    return 0;
}

