vector<string> rotate_clockwise(const vector<string> &s) {
    int n = s.size();
    vector<string> t(n, string(n, '.'));
    for (int i = 0; i < n; ++i) for (int j = 0; j < n; ++j) t[j][n - 1 - i] = s[i][j];
    return t;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int n;
    cin >> n;
    vector<string> s(n), t(n);
    for (auto &row : s) cin >> row;
    for (auto &row : t) cin >> row;
    int ans = 1e9;
    for (int rot = 0; rot < 4; ++rot) {
        int diff = 0;
        for (int i = 0; i < n; ++i) for (int j = 0; j < n; ++j) diff += (s[i][j] != t[i][j]);
        ans = min(ans, rot + diff);
        s = rotate_clockwise(s);
    }
    cout << ans << '\n';
    return 0;
}

