// 参考解：按题意实现核心算法。
int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int n, m;
    cin >> n >> m;
    vector<long long> cost(n);
    for (auto &x : cost) cin >> x;
    vector<vector<int>> animal(m);
    for (int i = 0; i < m; ++i) {
        int k;
        cin >> k;
        animal[i].resize(k);
        for (int &z : animal[i]) { cin >> z; --z; }
    }
    long long ans = numeric_limits<long long>::max();
    int total = 1;
    for (int i = 0; i < n; ++i) total *= 3;
    for (int mask = 0; mask < total; ++mask) {
        int x = mask;
        vector<int> visit(n, 0);
        long long cur = 0;
        for (int i = 0; i < n; ++i) {
            visit[i] = x % 3;
            x /= 3;
            cur += cost[i] * visit[i];
        }
        bool ok = true;
        for (const auto &zoos : animal) {
            int seen = 0;
            for (int z : zoos) seen += visit[z];
            if (seen < 2) ok = false;
        }
        if (ok) ans = min(ans, cur);
    }
    cout << ans << '\n';
    return 0;
}

