int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int n;
    long long l;
    cin >> n >> l;
    unordered_map<long long,long long> cnt;
    long long pos = 0;
    ++cnt[pos];
    for (int i = 1; i < n; ++i) {
        long long d;
        cin >> d;
        pos = (pos + d) % l;
        ++cnt[pos];
    }
    if (l % 3 != 0) {
        cout << 0 << '\n';
        return 0;
    }
    long long step = l / 3;
    auto get_count = [&](long long key) -> long long {
        auto it = cnt.find(key);
        return it == cnt.end() ? 0LL : it->second;
    };
    long long ans = 0;
    for (auto [p, c] : cnt) {
        long long p2 = (p + step) % l;
        long long p3 = (p + 2 * step) % l;
        ans += c * get_count(p2) * get_count(p3);
    }
    cout << ans / 3 << '\n';
    return 0;
}

