    int n, q;
    cin >> n >> q;
    vector<int> black(n + 2, 0);
    int intervals = 0;
    while (q--) {
        int a;
        cin >> a;
        if (!black[a]) {
            intervals += 1;
            if (black[a - 1]) --intervals;
            if (black[a + 1]) --intervals;
            black[a] = 1;
        } else {
